export type Loc = { en: string; fi: string; hu: string; sv: string };

export type IngredientRole =
	| 'protein' | 'carb' | 'vegetable' | 'fruit' | 'fat' | 'dairy'
	| 'legume' | 'seasoning' | 'liquid' | 'other';

export interface IngredientMacros {
	energy_kcal: number;
	protein_g: number;
	fat_g: number;
	carbohydrates_g: number;
	fiber_g: number;
	sugars_g: number;
	salt_g: number;
}

export interface IngredientMicros {
	potassium_mg: number; calcium_mg: number; iron_mg: number; magnesium_mg: number;
	phosphorus_mg: number; zinc_mg: number; selenium_ug: number; vitamin_a_rae_ug: number;
	vitamin_c_mg: number; vitamin_d_ug: number; vitamin_e_mg: number; vitamin_k_ug: number;
	thiamin_b1_mg: number; riboflavin_b2_mg: number; niacin_b3_mg: number; vitamin_b6_mg: number;
	folate_ug: number; vitamin_b12_ug: number; choline_mg: number;
}

export interface IngredientDietary {
	vegetarian: boolean;
	vegan: boolean;
	glutenFree: boolean;
	lactoseFree: boolean;
	nutFree: boolean;
	soyFree: boolean;
	dairyFree: boolean;
	containsRedMeat: boolean;
	containsPork: boolean;
	containsFish: boolean;
	fodmap: 'low' | 'moderate' | 'high';
	fodmapGroup?: string[];
}

export interface HouseholdUnit {
	unit: string;
	grams: number;
}

