const ingredientIndex: Map<string, Ingredient> = (() => {
	const m = new Map<string, Ingredient>();
	for (const ing of ingredients) {
		m.set(ing.id, ing);
		for (const a of ing.aliases ?? []) if (!m.has(a)) m.set(a, ing);
	}
	return m;
})();

export function getIngredient(idOrAlias: string): Ingredient | undefined {
	return ingredientIndex.get(idOrAlias);
}

